    import pyperclip
except ImportError:
    import subprocess
    subprocess.run('echo "osworld-public-evaluation" | sudo -S apt-get install -y xclip xsel', shell=True, check=True)
    subprocess.check_call([subprocess.sys.executable, '-m', 'pip', 'install', 'pyperclip'])
    import pyperclip

